const GS=()=><style>{`@import url('https://fonts.googleapis.com/css2?family=Source+Sans+3:wght@400;500;600;700;800;900&display=swap');*{margin:0;padding:0;box-sizing:border-box}html{scroll-behavior:smooth}body{font-family:${F};background:${C.bg};color:${C.t}}::-webkit-scrollbar{width:5px}::-webkit-scrollbar-thumb{background:${C.brd};border-radius:3px}input:focus,select:focus,textarea:focus{border-color:${C.g}!important;outline:none;box-shadow:0 0 0 3px ${C.gl}}button{transition:all .2s}button:active{transform:scale(.97)}@keyframes fadeUp{from{opacity:0;transform:translateY(16px)}to{opacity:1;transform:translateY(0)}}@keyframes float{0%,100%{transform:translateY(0)}50%{transform:translateY(-5px)}}@keyframes pulse{0%,100%{opacity:1}50%{opacity:.6}}@keyframes slideL{from{opacity:0;transform:translateX(-20px)}to{opacity:1;transform:translateX(0)}}@keyframes pop{from{opacity:0;transform:scale(.6)}to{opacity:1;transform:scale(1)}}.lift:hover{box-shadow:0 8px 28px rgba(27,138,74,.15);transform:translateY(-2px)}.glass{background:rgba(255,255,255,.72);backdrop-filter:blur(16px);-webkit-backdrop-filter:blur(16px);border:1px solid rgba(255,255,255,.45);box-shadow:0 4px 20px rgba(0,0,0,.06)}`}</style>;
const cd={background:"rgba(255,255,255,.72)",backdropFilter:"blur(16px)",borderRadius:16,padding:24,border:"1px solid rgba(255,255,255,.45)",boxShadow:"0 4px 20px rgba(0,0,0,.06)"};

function Field({label,value,onChange,type="text",placeholder="",half=false,options=null,rows=null}){const s={width:"100%",padding:"12px 16px",background:"rgba(240,247,240,.7)",border:`2px solid ${C.brd}`,borderRadius:10,color:C.t,fontSize:15,fontFamily:F,outline:"none",boxSizing:"border-box",backdropFilter:"blur(8px)",transition:"all .2s"};return <div style={{flex:half?"1 1 45%":"1 1 100%",minWidth:half?160:"auto"}}><label style={{display:"block",color:C.t,fontSize:13,fontWeight:700,marginBottom:6,fontFamily:F}}>{label}</label>{options?<select value={value} onChange={e=>onChange(e.target.value)} style={{...s,appearance:"auto"}}><option value="">— Choisir —</option>{options.map(o=><option key={o} value={o}>{o}</option>)}</select>:rows?<textarea value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder} rows={rows} style={{...s,resize:"vertical"}}/>:<input type={type} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder} style={s} autoComplete="off" spellCheck="false" data-lpignore="true" name={`f_${Math.random().toString(36).slice(2)}`}/>}</div>;}
function Btn({children,onClick,variant="primary",style:sx={}}){const v={primary:{padding:"14px 32px",background:`linear-gradient(135deg,${C.g},${C.gd})`,border:"none",borderRadius:12,color:C.w,fontSize:16,fontWeight:700,cursor:"pointer",fontFamily:F,boxShadow:`0 4px 20px ${C.g}40`},secondary:{padding:"12px 24px",background:"rgba(255,255,255,.8)",border:`2px solid ${C.g}`,borderRadius:12,color:C.g,fontSize:15,fontWeight:700,cursor:"pointer",fontFamily:F,backdropFilter:"blur(8px)"},yellow:{padding:"14px 32px",background:`linear-gradient(135deg,${C.y},${C.yd})`,border:"none",borderRadius:12,color:C.w,fontSize:16,fontWeight:700,cursor:"pointer",fontFamily:F,boxShadow:`0 4px 20px ${C.y}40`}};return <button onClick={onClick} className="lift" style={{...v[variant],...sx}}>{children}</button>;}
function Tri(){return <div style={{display:"flex",height:4}}><div style={{flex:1,background:"#000091"}}/><div style={{flex:1,background:"#FFF"}}/><div style={{flex:1,background:"#E1000F"}}/></div>}
function Toggle({checked,onChange,label,icon,color=C.g}){const rgb=color===C.g?"27,138,74":"245,166,35";return <div onClick={()=>onChange(!checked)} style={{padding:20,borderRadius:16,textAlign:"center",cursor:"pointer",transition:"all .3s",background:checked?`rgba(${rgb},.08)`:"rgba(255,255,255,.7)",border:`2px solid ${checked?color:C.brd}`,backdropFilter:"blur(12px)",boxShadow:checked?`0 4px 24px rgba(${rgb},.2)`:"0 2px 12px rgba(0,0,0,.04)"}}><div style={{fontSize:28,marginBottom:8}}>{icon}</div><div style={{fontSize:13,fontWeight:700,color:checked?color:C.m,fontFamily:F,marginBottom:12}}>{label}</div><div style={{width:52,height:28,borderRadius:14,margin:"0 auto",position:"relative",background:checked?`linear-gradient(135deg,${color},${color}CC)`:"linear-gradient(135deg,#D0D0D0,#B8B8B8)",boxShadow:checked?`0 2px 12px rgba(${rgb},.4),inset 0 1px 2px rgba(0,0,0,.1)`:"inset 0 2px 4px rgba(0,0,0,.15)",transition:"all .3s cubic-bezier(.23,1,.32,1)"}}><div style={{position:"absolute",top:3,left:checked?27:3,width:22,height:22,borderRadius:"50%",background:"#FFF",boxShadow:"0 2px 6px rgba(0,0,0,.2)",transition:"left .3s cubic-bezier(.23,1,.32,1)"}}/></div><div style={{fontSize:11,color:checked?color:C.lt,marginTop:8,fontWeight:600,fontFamily:F}}>{checked?"✓ Validé":"À valider"}</div></div>;}

// EARTH LOADER - CSS ONLY GLOBE
const EarthCSS=`
.earth-wrap{display:flex;flex-direction:column;align-items:center;justify-content:center;padding:40px;animation:fadeUp .4s ease both}
.earth-globe{width:120px;height:120px;border-radius:50%;position:relative;overflow:hidden;background:linear-gradient(135deg,#1a6fc4,#2989d8,#1a6fc4);box-shadow:inset -8px -4px 20px rgba(0,0,0,.3),inset 4px 4px 20px rgba(255,255,255,.2),0 8px 30px rgba(0,0,0,.15);border:3px solid rgba(255,255,255,.6);animation:earthSpin .8s ease-out}
.earth-land{position:absolute;width:200%;height:100%;top:0;left:0;animation:landScroll 4s linear infinite}
.earth-land-inner{position:absolute;width:50%;height:100%;top:0}
.earth-land-inner:nth-child(1){left:0}
.earth-land-inner:nth-child(2){left:50%}
.earth-c{position:absolute;border-radius:40% 60% 50% 50%;background:#3dbb6e}
.earth-shine{position:absolute;top:8px;left:12px;width:35px;height:35px;border-radius:50%;background:radial-gradient(circle,rgba(255,255,255,.35),transparent 70%);z-index:5}
@keyframes landScroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}
@keyframes earthSpin{0%{transform:scale(.5);opacity:0}100%{transform:scale(1);opacity:1}}
`;
